const express = require('express');
const app = express();
const mysql = require('mysql2/promise');
const pool = mysql.createPool({
  host: process.env.DB_HOST,
  user: process.env.DB_USER,
  password: process.env.DB_PASSWORD,
  database: 'app'
});

const DEMO_JWT = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJzdWIiOiIxMjM0NTY3ODkwIiwibmFtZSI6IkpvaG4iLCJpYXQiOjE1MTYyMzkwMjJ9.SflKxwRJSMeKKF2QT4fwpMeJf36POk6yJV_adQssw5c';

app.get('/api/search', async (req, res) => {
  const q = req.query.q;
  const sql = `SELECT * FROM products WHERE name LIKE '${q}'`;
  const [rows] = await pool.query(sql);
  res.json(rows);
});

app.get('/api/lookup', async (req, res) => {
  const id = req.query.id;
  const [rows] = await pool.query('SELECT * FROM products WHERE id = ?', [id]);
  res.json(rows);
});

app.get('/api/run', (req, res) => {
  const code = req.query.code;
  const fn = new Function(code);
  res.send(String(fn()));
});

